[CmdletBinding()]
param([ValidateSet('win-x64','linux-x64')][string]$RuntimeIdentifier='win-x64',[string]$Root=(Resolve-Path (Join-Path $PSScriptRoot '../..')).Path,[string]$OutputRoot=(Join-Path $Root 'artifacts/packages'),[switch]$AllowDirtySource)
$ErrorActionPreference='Stop';$Root=[IO.Path]::GetFullPath($Root);$componentRoot=Join-Path $Root 'implementations/kestrel-http2-websocket';$sourceRoot=Join-Path $componentRoot 'source';$stage=Join-Path $OutputRoot "kestrel-http2-websocket/$RuntimeIdentifier";$packageRoot=Join-Path $stage 'package';Remove-Item -LiteralPath $stage -Recurse -Force -ErrorAction SilentlyContinue;New-Item -ItemType Directory -Force (Join-Path $packageRoot "bin/$RuntimeIdentifier"),(Join-Path $packageRoot 'implementations'),(Join-Path $packageRoot 'certs'),(Join-Path $packageRoot 'third-party')|Out-Null;& dotnet publish (Join-Path $sourceRoot 'KestrelHttp2WebSocket.csproj') -c Release -r $RuntimeIdentifier --self-contained true -p:PublishSingleFile=true -p:DebugType=None -p:DebugSymbols=false -o (Join-Path $packageRoot "bin/$RuntimeIdentifier") --nologo;if($LASTEXITCODE-ne 0){throw 'Kestrel target publish failed'};Copy-Item (Join-Path $componentRoot 'protocol-lab-package.json'),(Join-Path $componentRoot 'protocol-lab.internal.json'),(Join-Path $componentRoot 'toolchain.json') $packageRoot;Copy-Item (Join-Path $componentRoot 'implementations/kestrel-http2-websocket.yaml') (Join-Path $packageRoot 'implementations');Copy-Item (Join-Path $componentRoot 'certs/*') (Join-Path $packageRoot 'certs');$sdkLine=(& dotnet --list-sdks|Select-Object -First 1);$sdkRoot=$sdkLine.Substring($sdkLine.IndexOf('[')+1).TrimEnd(']');$dotnetRoot=Split-Path $sdkRoot -Parent;Copy-Item (Join-Path $dotnetRoot 'LICENSE.txt'),(Join-Path $dotnetRoot 'ThirdPartyNotices.txt') (Join-Path $packageRoot 'third-party');$binary=if($RuntimeIdentifier-eq'win-x64'){'KestrelHttp2WebSocket.exe'}else{'KestrelHttp2WebSocket'};$entry=Join-Path $packageRoot 'implementations/kestrel-http2-websocket.yaml';$text=Get-Content $entry -Raw;$text=$text-replace'(?m)^executable:.*$',("executable: bin/$RuntimeIdentifier/$binary");$text=$text-replace'(?m)^entrypoint:.*$',("entrypoint: {kind: process, path: bin/$RuntimeIdentifier/$binary, arguments: